    public void clicked()
    {
        int infologLine = infolog.line();

        FormButtonControl bc = any2Object(this) as FormButtonControl;
        formdatasource    fds = bc.formRun().dataSource(tableStr(SubBillDeferralTransactionLineDeferral));

        next clicked();

        if(element.curTransactionType == SubBillDeferralTransactionType::VendInvoice && element.ubsAccountingDistribution.ubsAllowDeferral())
        {
            SubBillDeferralTransactionLineDeferral subBillDeferralTransactionLineDeferral = fds.cursor();
            subBillDeferralTransactionLineDeferral.ubsInitFromAccountingDistribution(element.args().record(), false);

            infolog.clear(infologLine);
        }
    }
